import{bV as a,aL as t,u as o,G as n}from"./chunks/framework.BQalybiP.js";const u=JSON.parse('{"title":"Level1 - Greetings and introductions","description":"","frontmatter":{"date":"2026-04-30T15:13:32.000Z","title":"Level1 - Greetings and introductions","categories":["英语","Speaking"]},"headers":[],"relativePath":"06.英语/Speaking/01.Level1 - Greetings and introductions.md","filePath":"06.英语/Speaking/01.Level1 - Greetings and introductions.md"}'),r={name:"06.英语/Speaking/01.Level1 - Greetings and introductions.md"};function i(s,e,p,d,l,h){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="leve1-greetings-and-introductions" tabindex="-1">Leve1 - Greetings and introductions <a class="header-anchor" href="#leve1-greetings-and-introductions" aria-label="Permalink to &quot;Leve1 - Greetings and introductions&quot;">​</a></h1><h3 id="问好" tabindex="-1">问好 <a class="header-anchor" href="#问好" aria-label="Permalink to &quot;问好&quot;">​</a></h3><p>我们经常会说 Hi 或者 Hello。</p><p><strong>Hello</strong>：可以用于任何<strong>正式</strong>或者<strong>非正式</strong>场合。</p><p><strong>Hi</strong>：用于<strong>非正式</strong>场合。</p><p>两者可以用于任何时间段。</p><h3 id="询问他人姓名" tabindex="-1">询问他人姓名 <a class="header-anchor" href="#询问他人姓名" aria-label="Permalink to &quot;询问他人姓名&quot;">​</a></h3><p>可以使用 What&#39;s your name?</p><p>**英文文化：**这里询问你的姓名的时候通常是询问名字而不是姓。</p><h3 id="介绍自己的名字" tabindex="-1">介绍自己的名字 <a class="header-anchor" href="#介绍自己的名字" aria-label="Permalink to &quot;介绍自己的名字&quot;">​</a></h3><p>使用 I&#39;m ... 或者 My name is ... 来告诉别人名字。</p><p>Eg. I&#39;m Jabin. / My name is Jabin.</p><p>My name is ... 相较于 I&#39;m 更为正式一点。</p><h3 id="与人初次见面时打招呼" tabindex="-1">与人初次见面时打招呼 <a class="header-anchor" href="#与人初次见面时打招呼" aria-label="Permalink to &quot;与人初次见面时打招呼&quot;">​</a></h3><p>Nice to meet you.</p><p>回答：Nice to meet you too.</p><h3 id="告别" tabindex="-1">告别 <a class="header-anchor" href="#告别" aria-label="Permalink to &quot;告别&quot;">​</a></h3><p>可以使用 Goodbye，有时也会使用简短形式 Bye，Bye 相对<strong>非正式</strong>一点。</p><h3 id="询问姓名拼写" tabindex="-1">询问姓名拼写 <a class="header-anchor" href="#询问姓名拼写" aria-label="Permalink to &quot;询问姓名拼写&quot;">​</a></h3><p>How do you spell your first name?</p><p>回答：It&#39;s ...</p><h3 id="询问电话号码" tabindex="-1">询问电话号码 <a class="header-anchor" href="#询问电话号码" aria-label="Permalink to &quot;询问电话号码&quot;">​</a></h3><p>What&#39;s your telephone/phone/cellphone/空 number?</p><p>回答：It&#39;s ...</p><p>这里如果中间含有0，口语可以用 oh 代替 zero。</p><h3 id="问好-1" tabindex="-1">问好 <a class="header-anchor" href="#问好-1" aria-label="Permalink to &quot;问好&quot;">​</a></h3><p><strong>问候语：</strong></p><p>中午之前：Good morning.</p><p>中午到下午六点：Good afternoon.</p><p>下午六点到午夜：Good evening.</p><p>使用 Good night 在晚上对某人说再见或者用来表示要去睡觉了。</p><p>在比较正式的场合使用 How are you 进行问候。</p><p>回答的时候使用：I&#39;m fine, thanks. And you? / I&#39;m good.</p><p>结束早上的对话，可以对其说希望他能有愉快的一天。Have a nice day.</p>',34)])])}const g=a(r,[["render",i]]);export{u as __pageData,g as default};
